+            if (has_sum) { s1 += @floatFromInt(v1); s2 += @floatFromInt(v2); s3 += @floatFromInt(v3); s4 += @floatFromInt(v4); }
+            if (has_min or has_max) {
+                const f1: Vec4f64 = @floatFromInt(v1);
+                const f2: Vec4f64 = @floatFromInt(v2);
