+                if (has_max) self.max_vec = @max(self.max_vec, @max(@max(f1, f2), @max(f3, f4)));
+            }
+        }
+        if (has_sum) self.sum_vec += (s1 + s2 + s3 + s4);
+        if (self.metrics.count) self.count += i;
+        
+        while (i + 4 <= len) : (i += 4) {
+            const v: @Vector(4, i64) = ptr[i..i+4][0..4].*;
